/**
 * Anthropic message with OpenRouter extensions
 */
export const zMessagesMessageParam = z.object({
  content: z.union([
    z.string(),
    z.array(
      z.union([
        zAnthropicTextBlockParam,
        zAnthropicImageBlockParam,
        zAnthropicDocumentBlockParam,
        z.object({
          cache_control: zAnthropicCacheControlDirective.optional(),
          id: z.string(),
          input: z.unknown().optional(),
          name: z.string(),
          type: z.enum(['tool_use']),
        }),
        z.object({
          cache_control: zAnthropicCacheControlDirective.optional(),
          content: z
            .union([
              z.string(),
              z.array(
                z.union([
                  zAnthropicTextBlockParam,
                  zAnthropicImageBlockParam,
                  z.object({
                    tool_name: z.string(),
                    type: z.enum(['tool_reference']),
                  }),
                  zAnthropicSearchResultBlockParam,
                  zAnthropicDocumentBlockParam,
                ]),
              ),
            ])
            .optional(),
          is_error: z.boolean().optional(),
          tool_use_id: z.string(),
          type: z.enum(['tool_result']),
        }),
        z.object({
          signature: z.string(),
          thinking: z.string(),
          type: z.enum(['thinking']),
        }),
        z.object({
          data: z.string(),
          type: z.enum(['redacted_thinking']),
        }),
        z.object({
          cache_control: zAnthropicCacheControlDirective.optional(),
          id: z.string(),
          input: z.unknown().optional(),
          name: z.string(),
          type: z.enum(['server_tool_use']),
        }),
        z.object({
          cache_control: zAnthropicCacheControlDirective.optional(),
          content: z.union([
            z.array(zAnthropicWebSearchResultBlockParam),
            z.object({
              error_code: z.enum([
                'invalid_tool_input',
                'unavailable',
                'max_uses_exceeded',
                'too_many_requests',
                'query_too_long',
              ]),
              type: z.enum(['web_search_tool_result_error']),
            }),
          ]),
          tool_use_id: z.string(),
          type: z.enum(['web_search_tool_result']),
        }),
        zAnthropicSearchResultBlockParam,
        z.object({
          cache_control: zAnthropicCacheControlDirective.optional(),
          content: z.string().nullable(),
          type: z.enum(['compaction']),
        }),
        zMessagesAdvisorToolResultBlock,
      ]),
    ),
  ]),
  role: z.enum(['user', 'assistant', 'system']),
})

