/**
 * Stop when the upstream model emits this finish reason (e.g. `length`).
 */
export const zStopServerToolsWhenFinishReasonIs = z.object({
  reason: z.string().min(1),
  type: z.enum(['finish_reason_is']),
})

/**
 * Stop after a tool with this name has been called.
 */
export const zStopServerToolsWhenHasToolCall = z.object({
  tool_name: z.string().min(1),
  type: z.enum(['has_tool_call']),
})

/**
 * Stop once cumulative cost across the loop exceeds this dollar threshold.
 */
export const zStopServerToolsWhenMaxCost = z.object({
  max_cost_in_dollars: z.number(),
  type: z.enum(['max_cost']),
})

/**
 * Stop once cumulative token usage across the loop exceeds this threshold.
 */
export const zStopServerToolsWhenMaxTokensUsed = z.object({
  max_tokens: z.int(),
  type: z.enum(['max_tokens_used']),
})

/**
 * Stop after the agent loop has executed this many steps.
 */
export const zStopServerToolsWhenStepCountIs = z.object({
  step_count: z.int(),
  type: z.enum(['step_count_is']),
})

/**
 * A single condition that, when met, halts the server-tool agent loop.
 */
export const zStopServerToolsWhenCondition = z.discriminatedUnion('type', [
  zStopServerToolsWhenStepCountIs.extend({ type: z.literal('step_count_is') }),
  zStopServerToolsWhenHasToolCall.extend({ type: z.literal('has_tool_call') }),
  zStopServerToolsWhenMaxTokensUsed.extend({
    type: z.literal('max_tokens_used'),
  }),
  zStopServerToolsWhenMaxCost.extend({ type: z.literal('max_cost') }),
  zStopServerToolsWhenFinishReasonIs.extend({
    type: z.literal('finish_reason_is'),
  }),
])

/**
 * Stop conditions for the server-tool agent loop. Any condition firing halts the loop (OR logic). When set, this overrides `max_tool_calls`.
 */
export const zStopServerToolsWhen = z
  .array(zStopServerToolsWhenCondition)
  .min(1)

